var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"여론을 잠재우기 위해 대역을 마련할 테니, 코핀 측에서는 가짜 보물을 준비할 것.","JPN":"世論を鎮めるために代役をこちらが用意する。コフィンには偽の宝箱を用意することを要請いたす。","ENG":"A stand-in will be provided to calm the public, so Coffin Company is to prepare a fake treasure chest.","TWN":"為了平息輿論，我們會安排替身，科芬公司方面準備假的寶箱。"},"stage":{"bg":"OFFICE_TOP","slots":{"L":null,"C":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"그 외 잡음은 알파트릭스와 아카데미 측의 협력을 받는 것으로 해당 사건은 종결한다.","JPN":"その他いくつか存在するトラブルについては、アルファトリックスとアカデミーと協同し、それをもって当該事件は収束とする。","ENG":"The case will be closed by receiving the help of Alphatrix and the Academy to drown out the remaining noise.","TWN":"其他雜音將透過阿爾法崔克斯和學院方面來合作解決，此次事件就到此結束。"},"stage":{"bg":"OFFICE_TOP","slots":{"L":null,"C":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"그라운드 원 시니어의 답변은 이상입니다. 프론트베이 측의 서신도 읽어드릴까요?","JPN":"グラウンド・ワンのシニアからの回答はここまでです。フロントベイからの答弁書も読み上げた方がよろしいでしょうか？","ENG":"And that was the reply from Ground One's Senior. Would you like me to read the letter from Front Bay?","TWN":"G1那邊的高層回覆就是這樣。要不要也讀一下前灣那邊的信件？"},"stage":{"bg":"OFFICE_TOP","slots":{"L":null,"C":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"됐습니다. 그 인간이라면 분명 호탕하게 넘어갈 테죠.","JPN":"いいえ、大丈夫です。あの方はどうせ笑い飛ばすでしょうから。","ENG":"It's all right. I'm sure he would not have taken this too seriously.","TWN":"不用了，那個人肯定會爽快答應的。"},"stage":{"bg":"OFFICE_TOP","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"두껍게 쌓인 양에 비해 알맹이는 꽤나 간략하군요.","JPN":"分厚い資料を用意した割りに、出てきた回答は以外とあっさりとしていますね。","ENG":"The summary is quite brief compared to the amount of paper that is stacked.","TWN":"雖然看著一堆，內容卻相當簡略嘛。"},"stage":{"bg":"OFFICE_TOP","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"음… 사실 다른 말도 적혀 있긴 한데 대부분 안 좋은 말이라서요.","JPN":"ふむ……本当はもっと色々書かれてはいるのですが、申し上げにくい内容ばかりでして。","ENG":"Well... There are some other comments, but mostly negative.","TWN":"嗯……其實還有其他內容，不過大部分都是不好的話。"},"stage":{"bg":"OFFICE_TOP","slots":{"L":null,"C":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"바쁘실 테니 대충 요약하자면.","JPN":"お忙しいと思うので、短く要約してお伝えしますと……","ENG":"Since you are busy as it is, I will try to make it short.","TWN":"畢竟副總你很忙，我可以簡單總結一下，"},"stage":{"bg":"OFFICE_TOP","slots":{"L":null,"C":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"이번에는 넘어가지만 다음에도 이러면 진짜 영업정지인 줄 알아라. 라고…….","JPN":"今回は大目に見てやるが、次は営業停止をくらわせるぞ。とのことです……","ENG":"It could be reduced to, \\"I'll let it slide this time, but we'll close you down if this happens again...\\"","TWN":"這次不跟你計較，下次再這樣的話，真的會讓你停業的，差不多這類的話……"},"stage":{"bg":"OFFICE_TOP","slots":{"L":null,"C":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"하아…….","JPN":"はぁ……","ENG":"*Sigh*","TWN":"哀哀……"},"stage":{"bg":"OFFICE_TOP","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"아무튼 고생하셨습니다. 이제야 겨우 한 숨 돌릴 수 있겠군요.","JPN":"とにかく、お疲れ様でした。ようやく一息つけそうですね。","ENG":"Anyway. Good work. I can finally take a breather.","TWN":"總之，大家辛苦了。現在終於可以稍微喘口氣了。"},"stage":{"bg":"OFFICE_TOP","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"하나 씨는 이만 들어가세요.","JPN":"ナカシマさんはお帰りいただいて結構ですよ。","ENG":"Hana, you can go now.","TWN":"荷娜你回去吧。"},"stage":{"bg":"OFFICE_TOP","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"네. 부사장님도 고생하셨어요.","JPN":"はい、副社長。お疲れ様でした。","ENG":"Thank you. You should get some rest too.","TWN":"是，副總你也辛苦了。"},"stage":{"bg":"OFFICE_TOP","slots":{"L":null,"C":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"그래서.","JPN":"で。","ENG":"So.","TWN":"我就問，"},"stage":{"bg":"OFFICE_TOP","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"두 분은 언제까지 그 뒤에 숨어 있을 겁니까?","JPN":"お二人はいつまでそこに隠れているつもりですか？","ENG":"How much longer are you two planning to hide there?","TWN":"你們兩位打算躲在後面到什麼時候？"},"stage":{"bg":"OFFICE_TOP","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"회사는 놀이터가 아니라고 몇 번이나 말했을 텐데요.","JPN":"会社は遊ぶ場所ではないと、何度も言ったはずですが。","ENG":"I've mentioned several times that the company is not a playground.","TWN":"我說過多少次了，公司不是遊樂園。"},"stage":{"bg":"OFFICE_TOP","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"SIGMA_RAS_NULL_NULL","text":{"KOREA":"아, 걸렸다.","JPN":"あ、バレてる。","ENG":"Oh, she found us.","TWN":"啊，被發現了。"},"stage":{"bg":"OFFICE_TOP","slots":{"L":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"아하하… 걸렸네요.","JPN":"あはは、バレていましたね。","ENG":"Ah ha ha... You got us.","TWN":"哈哈哈……被發現了。"},"stage":{"bg":"OFFICE_TOP","slots":{"L":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"오랜만입니다, 유피 양.","JPN":"お久しぶりですね、ユピさん。","ENG":"It's been a while, Yuppie.","TWN":"好久不見，悠菲。"},"stage":{"bg":"OFFICE_TOP","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"보아하니 재판은 잘 마무리된 모양이군요.","JPN":"裁判がうまくいったようで、なによりです。","ENG":"I assume your trial went well.","TWN":"看來審判順利結束了呢。"},"stage":{"bg":"OFFICE_TOP","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"덕분이죠. 부사장님이 알파트릭스 회장님을 소개해 주신 덕에 일이 쉽게 풀렸거든요.","JPN":"裁判がうまくいったのは、副社長がアルファトリックス会長をご紹介してくださっておけがです。","ENG":"Thanks to you. Things worked out smoothly after you introduced me to the President of Alphatrix.","TWN":"多虧副總你介紹了阿爾法崔克斯的會長，事情才能順利解決。"},"stage":{"bg":"OFFICE_TOP","slots":{"L":null,"C":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"누명에 대한 보상으로 빚도 갚았으니 이젠 진짜 자유의 몸이에요.","JPN":"冤罪に対する賠償金のおかげで、借金も完済できたので、いよいよ本当に自由の身になりました。","ENG":"Since they compensated me for the framing, I'm truly free now.","TWN":"我拿被誣告的獲得的賠償金去還清債務，現在我的是自由之身了。"},"stage":{"bg":"OFFICE_TOP","slots":{"L":null,"C":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"감사합니다. 블루로즈 섬에서 나올 때도 그랬지만 이것저것 도움만 받네요.","JPN":"本当にありがとうございました。ブルーローズ島から脱出するときもそうでしたが、助けていただいてばかりです。","ENG":"Thank you. You've been helping so much, including when we left Blue Rose Island.","TWN":"謝謝。不僅是從藍玫瑰島回來的時候，這次也得到很多幫助呢。"},"stage":{"bg":"OFFICE_TOP","slots":{"L":null,"C":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"별거 아닙니다. 그 정도는 딱히 내세울 만한 일도 아니고요.","JPN":"いいえ。そんな大したことをやったつもりはありません。","ENG":"It's not a big deal. Nothing to show off.","TWN":"沒什麼，區區小事不足掛齒。"},"stage":{"bg":"OFFICE_TOP","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"그나저나 곧 그라운드원을 떠난다고 들었습니다만?","JPN":"ところで、もうすぐグラウンドワンを離れると聞きましたよ？","ENG":"Anyway, I heard you were leaving Ground One soon.","TWN":"話說回來，聽說你們很快就要離開G1了？"},"stage":{"bg":"OFFICE_TOP","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"네. 여기서의 일도 해결했으니 저도 크레데레처럼 고향으로 돌아가려고요.","JPN":"はい、ここでの事件は解決したので、私もクレデレのように故郷に帰ろうかなと。","ENG":"Yeah. Since my business here is done, I'm going back to my hometown like Credere.","TWN":"嗯。這裡的事情也解決了，我也打算像克蕾妲莉一樣回到家鄉。"},"stage":{"bg":"OFFICE_TOP","slots":{"L":null,"C":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"코핀에서 일해도 된다는 제안은 감사하지만… 역시 먼 타지에서 일하는 건 적성에 안 맞나 봐요.","JPN":"コフィンで働いてもいいとご提案いただいたのはとても有難いのですが……やっぱり遠く離れた街で働くのは自分に向いていないような気がして。","ENG":"I appreciate the job offer for Coffin Company, but... I don't think I'm fit to work somewhere far from home.","TWN":"感謝你們讓我在科芬公司工作的提議……不過，果然在離家太遠的地方工作不太適應。"},"stage":{"bg":"OFFICE_TOP","slots":{"L":null,"C":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"SIGMA_RAS_NULL_NULL","text":{"KOREA":"으음… 그래도 언제든 놀러 와도 돼?","JPN":"ん……でも、またいつでも遊びにきていいんだよ？","ENG":"Mm... Still, you can visit any time!","TWN":"嗯……不過，悠菲隨時都可以來玩喔？"},"stage":{"bg":"OFFICE_TOP","slots":{"L":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};